#!/usr/bin/env python3
"""
DGX DEPLOY v19.34.241 — hygiene: also reject reconciliation/import setup_types.

Idempotent: rewrites the embedded files, runs the v240 pytest under .venv,
then git commit && git push (REQUIRED — the .bat restart runs `git checkout -- .`
which wipes uncommitted work), then ./start_backend.sh --force.

Does NOT run the data backfill — run that separately AFTER deploy:
  .venv/bin/python backend/scripts/backfill_v19_34_240_hygiene.py --dry-run
  .venv/bin/python backend/scripts/backfill_v19_34_240_hygiene.py

Run on the DGX repo root:  .venv/bin/python /tmp/deploy_v19_34_240.py
"""
import base64, gzip, os, subprocess, sys

FILES = {
    'backend/services/trade_outcome_hygiene.py': '',
    'backend/services/pnl_compute.py': '',
    'backend/services/gameplan_edge_ranker.py': '',
    'backend/scripts/backfill_v19_34_240_hygiene.py': '',
    'backend/tests/test_v19_34_240_outcome_hygiene.py': '',
}

REPO = os.getcwd()

def main():
    if not os.path.isdir(os.path.join(REPO, "backend", "services")):
        print(f"[FATAL] not a repo root (no backend/services): {REPO}")
        sys.exit(1)
    for rel, b in FILES.items():
        dst = os.path.join(REPO, rel)
        os.makedirs(os.path.dirname(dst), exist_ok=True)
        data = gzip.decompress(base64.b64decode(b))
        with open(dst, "wb") as f:
            f.write(data)
        print(f"[WROTE] {rel} ({len(data)} bytes)")

    print("[TEST] running v240 + v239 pytest ...")
    r = subprocess.run(
        [sys.executable, "-m", "pytest",
         "backend/tests/test_v19_34_240_outcome_hygiene.py",
         "backend/tests/test_v19_34_233_gameplan_edge_rank.py", "-q"],
        cwd=REPO)
    if r.returncode != 0:
        print("[FATAL] pytest failed — aborting BEFORE commit/restart.")
        sys.exit(2)

    subprocess.run(["git", "add"] + list(FILES.keys()), cwd=REPO)
    c = subprocess.run(
        ["git", "commit", "-m",
         "v19.34.241 — hygiene: reject reconciliation/import setup_types (reconciled_*, imported_from_ib)"],
        cwd=REPO)
    if c.returncode != 0:
        print("[INFO] git commit no-op (already committed) — continuing.")
    p = subprocess.run(["git", "push"], cwd=REPO)
    if p.returncode != 0:
        print("[WARN] git push failed — commit is LOCAL; push manually.")

    print("[RESTART] ./start_backend.sh --force")
    subprocess.run(["./start_backend.sh", "--force"], cwd=REPO)
    print("[DONE] v19.34.241 deployed. Re-run the backfill --dry-run to confirm reconciled_* are gone, then commit it.")

if __name__ == "__main__":
    main()
